/************************************
 * Set urls of parent case documents 
 * 
 * by Cinthia Romero
 * modified by Adriana Centellas
 ***********************************/

// Get current URL
var currentUrl = window.location.href;
var environmentUrl = currentUrl.split("/")[0];
var parentRequestID = this._request.id;
var documentsUrl = {};

// Function to generate download links if files exist
function getDocumentLinks(fileArray, environmentUrl, parentRequestID) {
    if (Array.isArray(fileArray)) {
        return fileArray.map(fileObj => 
            "<a href='" + environmentUrl + "/request/" + parentRequestID + "/files/" + fileObj.file + "'>Download</a>"
        ).join("<br>");
    } else if (fileArray != null && typeof fileArray === 'object' && fileArray.file) {
        return "<a href='" + environmentUrl + "/request/" + parentRequestID + "/files/" + fileArray.file + "'>Download</a>";
    } else {
        // Fallback in case it's a single ID or invalid format
        return "<a href='" + environmentUrl + "/request/" + parentRequestID + "/files/" + fileArray + "'>Download</a>";
    }
}

// Validate and generate links for each document type

if (
    (Array.isArray(this.PE_UPLOAD_IC_PRESENTATION) && this.PE_UPLOAD_IC_PRESENTATION.length > 0) ||
    (!Array.isArray(this.PE_UPLOAD_IC_PRESENTATION) && this.PE_UPLOAD_IC_PRESENTATION != null)
) {
    documentsUrl["IC_PRESENTATION_DOCUMENT"] = getDocumentLinks(this.PE_UPLOAD_IC_PRESENTATION, environmentUrl, parentRequestID);
}

if (
    this.PE_UPLOAD_DD_REC_NA !== true &&
    (
        (Array.isArray(this.PE_UPLOAD_DD_REC) && this.PE_UPLOAD_DD_REC.length > 0) ||
        (!Array.isArray(this.PE_UPLOAD_DD_REC) && this.PE_UPLOAD_DD_REC != null)
    )
) {
    documentsUrl["DD_REC_DOCUMENT"] = getDocumentLinks(this.PE_UPLOAD_DD_REC, environmentUrl, parentRequestID);
}

if (
    this.PE_UPLOAD_BEAT_UP_NA !== true &&
    (
        (Array.isArray(this.PE_UPLOAD_BEAT_UP) && this.PE_UPLOAD_BEAT_UP.length > 0) ||
        (!Array.isArray(this.PE_UPLOAD_BEAT_UP) && this.PE_UPLOAD_BEAT_UP != null)
    )
) {
    documentsUrl["BEAT_UP_DOCUMENT"] = getDocumentLinks(this.PE_UPLOAD_BEAT_UP, environmentUrl, parentRequestID);
}

if (
    this.PE_UPLOAD_BLACK_HAT_NA !== true &&
    (
        (Array.isArray(this.PE_UPLOAD_BLACK_HAT) && this.PE_UPLOAD_BLACK_HAT.length > 0) ||
        (!Array.isArray(this.PE_UPLOAD_BLACK_HAT) && this.PE_UPLOAD_BLACK_HAT != null)
    )
) {
    documentsUrl["BLACK_HAT_DOCUMENT"] = getDocumentLinks(this.PE_UPLOAD_BLACK_HAT, environmentUrl, parentRequestID);
}

return documentsUrl;
